# Rate limiting (basic implementation)
request_counts = {}

def rate_limit_check(ip_address, limit=100, window=60):
    current_time = datetime.utcnow()
    
    if ip_address not in request_counts:
        request_counts[ip_address] = []
    
    # Remove old requests outside the time window
    request_counts[ip_address] = [
        req_time for req_time in request_counts[ip_address]
        if (current_time - req_time).seconds < window
    ]
    
    if len(request_counts[ip_address]) >= limit:
        return False
    
    request_counts[ip_address].append(current_time)
    return True

# Custom GraphQL view with security measures
class SecureGraphQLView(GraphQLView):
    def dispatch_request(self):
        # Rate limiting
        ip_address = request.remote_addr
        if not rate_limit_check(ip_address):
            return {'errors': [{'message': 'Rate limit exceeded'}]}, 429
        
        # Query depth limiting
        query = request.get_json().get('query', '') if request.is_json else ''
        if query.count('{') > 10:  # Simple depth check
            return {'errors': [{'message': 'Query too complex'}]}, 400
        
        # Query size limiting
        if len(query) > 10000:
            return {'errors': [{'message': 'Query too large'}]}, 400
        
        return super().dispatch_request()

